package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package controllers;

import Services.UserService;
import entities.User;
import utils.SessionManager;
import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;
import java.sql.SQLDataException;

public class MainFX extends Application {

    private static Stage primaryStage;
    private static User authenticatedUser;

    public static void switchToAuthLandingView() {
        authenticatedUser = null;
        switchScene("/views/auth/Landing.fxml", "/views/styles/auth.css", "Artium");
    }

    public static void switchToLoginView() {
        authenticatedUser = null;
        switchScene("/views/auth/Connexion.fxml", "/views/styles/auth.css", "Artium | Connexion");
    }

    public static void switchToRegistrationView() {
        authenticatedUser = null;
        switchScene("/views/pages/inscription.fxml", "/views/styles/auth.css", "Artium | Inscription");
    }

    public static void switchToForgotPasswordView() {
        authenticatedUser = null;
        switchScene("/views/auth/ForgotPassword.fxml", "/views/styles/auth.css", "Artium | Mot de passe oublie");
    }

    public static void switchToArtistView() {
        authenticatedUser = null;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToArtistView(User user) {
        authenticatedUser = user;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToAdminView() {
        authenticatedUser = null;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAdminView(User user) {
        authenticatedUser = user;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAmateurView() {
        authenticatedUser = null;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static void switchToAmateurView(User user) {
        authenticatedUser = user;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static User getAuthenticatedUser() {
        return authenticatedUser;
    }

    private static void switchScene(String fxmlPath, String stylesheetPath, String title) {
        if (primaryStage == null) {
            return;
        }
        try {
            FXMLLoader loader = new FXMLLoader(MainFX.class.getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = new Scene(root);
            URL stylesheet = Objects.requireNonNull(MainFX.class.getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().add(stylesheet.toExternalForm());
            primaryStage.setTitle(title);
            primaryStage.setScene(scene);
            primaryStage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }

    public void start(Stage stage) {
        primaryStage = stage;
        // Taille minimale globale pour garder le layout lisible, sans figer la taille des scenes.
        primaryStage.setMinWidth(1100);
        primaryStage.setMinHeight(650);

        try {
            new UserService().ensureDefaultAdminAccount();
        } catch (SQLDataException e) {
            System.err.println("Impossible d'initialiser le compte admin par défaut: " + e.getMessage());
        }

        // Vérifier si une session persistante existe
        User sessionUser = SessionManager.getCurrentUser();
        if (sessionUser != null && sessionUser.getId() != null) {
            // Utilisateur connecté, rediriger vers le dashboard approprié
            authenticatedUser = sessionUser;
            redirectToUserDashboard(sessionUser);
        } else {
            // Aucune session, afficher la page d'accueil
            switchToAuthLandingView();
        }
    }

    private void redirectToUserDashboard(User user) {
        String role = user.getRole() == null ? "" : user.getRole().trim().toLowerCase();
        switch (role) {
            case "amateur":
                switchToAmateurView(user);
                break;
            case "artiste":
            case "artist":
                switchToArtistView(user);
                break;
            case "admin":
                switchToAdminView(user);
                break;
            default:
                switchToAuthLandingView();
        }
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package controllers;

import Services.UserService;
import entities.User;
import utils.SessionManager;
import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;
import java.sql.SQLDataException;

public class MainFX extends Application {

    private static Stage primaryStage;
    private static User authenticatedUser;

    public static void switchToAuthLandingView() {
        authenticatedUser = null;
        switchScene("/views/auth/Landing.fxml", "/views/styles/auth.css", "Artium");
    }

    public static void switchToLoginView() {
        authenticatedUser = null;
        switchScene("/views/auth/Connexion.fxml", "/views/styles/auth.css", "Artium | Connexion");
    }

    public static void switchToRegistrationView() {
        authenticatedUser = null;
        switchScene("/views/pages/inscription.fxml", "/views/styles/auth.css", "Artium | Inscription");
    }

    public static void switchToForgotPasswordView() {
        authenticatedUser = null;
        switchScene("/views/auth/ForgotPassword.fxml", "/views/styles/auth.css", "Artium | Mot de passe oublie");
    }

    public static void switchToArtistView() {
        authenticatedUser = null;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToArtistView(User user) {
        authenticatedUser = user;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToAdminView() {
        authenticatedUser = null;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAdminView(User user) {
        authenticatedUser = user;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAmateurView() {
        authenticatedUser = null;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static void switchToAmateurView(User user) {
        authenticatedUser = user;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static User getAuthenticatedUser() {
        return authenticatedUser;
    }

    private static void switchScene(String fxmlPath, String stylesheetPath, String title) {
        if (primaryStage == null) {
            return;
        }
        try {
            FXMLLoader loader = new FXMLLoader(MainFX.class.getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = primaryStage.getScene();
            if (scene == null) {
                scene = new Scene(root);
                primaryStage.setScene(scene);
            } else {
                scene.setRoot(root);
            }
            URL stylesheet = Objects.requireNonNull(MainFX.class.getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().setAll(stylesheet.toExternalForm());
            primaryStage.setTitle(title);
            primaryStage.setMaximized(true);
            primaryStage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }

    public void start(Stage stage) {
        primaryStage = stage;
        // Taille minimale globale pour garder le layout lisible, sans figer la taille des scenes.
        primaryStage.setMinWidth(1100);
        primaryStage.setMinHeight(650);
        primaryStage.setMaximized(true);

        try {
            new UserService().ensureDefaultAdminAccount();
        } catch (SQLDataException e) {
            System.err.println("Impossible d'initialiser le compte admin par défaut: " + e.getMessage());
        }

        // Vérifier si une session persistante existe
        User sessionUser = SessionManager.getCurrentUser();
        if (sessionUser != null && sessionUser.getId() != null) {
            // Utilisateur connecté, rediriger vers le dashboard approprié
            authenticatedUser = sessionUser;
            redirectToUserDashboard(sessionUser);
        } else {
            // Aucune session, afficher la page d'accueil
            switchToAuthLandingView();
        }
    }

    private void redirectToUserDashboard(User user) {
        String role = user.getRole() == null ? "" : user.getRole().trim().toLowerCase();
        switch (role) {
            case "amateur":
                switchToAmateurView(user);
                break;
            case "artiste":
            case "artist":
                switchToArtistView(user);
                break;
            case "admin":
                switchToAdminView(user);
                break;
            default:
                switchToAuthLandingView();
        }
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package controllers.amateur;

import controllers.MainFX;
import utils.SessionManager;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.MenuButton;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;
import java.util.function.Consumer;

public class NavbarAmateurController {

    @FXML
    private Button anchorButton;

    @FXML
    private Button notificationsButton;

    @FXML
    private MenuButton oeuvresButton;

    @FXML
    private Button bibliothequeButton;

    @FXML
    private Button musiqueButton;

    private Consumer<String> navigationHandler;
    private Consumer<Boolean> themeHandler;

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setThemeHandler(Consumer<Boolean> themeHandler) {
        this.themeHandler = themeHandler;
    }

    public void setActiveRoute(String route) {
        oeuvresButton.getStyleClass().remove("active");
        bibliothequeButton.getStyleClass().remove("active");
        musiqueButton.getStyleClass().remove("active");

        if (route.startsWith("feed")) {
            oeuvresButton.getStyleClass().add("active");
        } else if ("bibliotheque".equals(route) || "book-reader".equals(route)) {
            bibliothequeButton.getStyleClass().add("active");
        } else if ("musique".equals(route)) {
            musiqueButton.getStyleClass().add("active");
        }
    }

    @FXML
    private void onFeedClick() {
        navigate("feed");
    }

    @FXML
    private void onFeedPeinturesClick() {
        navigate("feed-peintures");
    }

    @FXML
    private void onFeedSculpturesClick() {
        navigate("feed-sculptures");
    }

    @FXML
    private void onFeedPhotosClick() {
        navigate("feed-photos");
    }

    @FXML
    private void onFeedRecommendationsClick() {
        navigate("feed-recommandations");
    }

    @FXML
    private void onBibliothequeClick() {
        navigate("bibliotheque");
    }

    @FXML
    private void onMusiqueClick() {
        navigate("musique");
    }

    @FXML
    private void onThemeLight() {
        if (themeHandler != null) {
            themeHandler.accept(false);
        }
    }

    @FXML
    private void onThemeDark() {
        if (themeHandler != null) {
            themeHandler.accept(true);
        }
    }

    @FXML
    private void onNotificationsClick() {
        notificationsButton.setText("!!");
    }

    @FXML
    private void onSwitchToAdminView() {
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    @FXML
    private void onSwitchToArtistView() {
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    @FXML
    private void onSwitchToAmateurView() {
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

	@FXML
	private void onLogoutClick() {
		// Effacer la session persistante
		SessionManager.clearSession();
		// Rediriger vers la page d'authentification
		MainFX.switchToLoginView();
	}

    private void navigate(String route) {
        if (navigationHandler != null) {
            navigationHandler.accept(route);
        }
    }

    private void switchScene(String fxmlPath, String stylesheetPath, String title) {
        Stage stage = (Stage) anchorButton.getScene().getWindow();
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = new Scene(root);
            URL stylesheet = Objects.requireNonNull(getClass().getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().add(stylesheet.toExternalForm());
            stage.setTitle(title);
            stage.setScene(scene);
            stage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }
}

